97	void uc_batch_dl_finite_difference_impl_t::prove(const std::vector<ecc_point_t>& Q, const std::vector<bn_t>& w,
98	                                                 mem_t session_id, uint64_t aux) {
99	  int n = int(w.size());
100	  if (n <= 28) {
101	    params.rho = 43;
102	    params.b = 3 + int_log2(n);
103	  } else {
104	    params.rho = 64;
105	    params.b = 2 + int_log2(n);
106	  }
107	  params.t = params.b + 5;
108	
109	  std::vector<bn_t> r(params.rho);
110	  ecurve_t curve = Q[0].get_curve();
111	  const auto& G = curve.generator();
112	  const mod_t& q = curve.order();
113	
114	  std::vector<bn_t> pw0;
115	  pw0.push_back(0);
116	  std::vector<bn_t> pw1;
117	  for (int j = 0; j < n; j++) {
118	    cb_assert(w[j] < q && "w[j] exceeds the order of the curve");
119	    if ((j % 2) == 0)
120	      pw1.push_back(w[j]);
121	    else
122	      pw0.push_back(w[j]);
123	  }
124	
125	  int rho = params.rho;
126	  R.resize(rho);
127	  e.resize(rho);
128	  z.resize(rho);
129	
130	  bn_t q_value = bn_t(q);
131	  buf_t common_hash;
132	  bn_t ri, z_tag;
133	
134	  int n_half = (n + 1) / 2;
135	  matrix_sum_t matrix_sum(n);
136	  vector_sum_t sum(n, params.t);
137	
138	  for (int ei = 0; ei <= n_half; ei++) {
139	    bn_t ei_square = ei * ei;
140	    bn_t alpha = crypto::horner_poly(q, pw0, ei_square);
141	    bn_t beta = crypto::horner_poly(q, pw1, ei_square);
142	    MODULO(q) {
143	      sum[ei] = matrix_sum[ei][0] = alpha + beta * ei;    // for positive
144	      sum[-ei] = matrix_sum[-ei][0] = alpha - beta * ei;  // for negative
145	    }
146	  }
147	  int k = n_half;
148	  std::vector<bn_t>* last = &matrix_sum[n_half];
149	  std::vector<bn_t>* current = &matrix_sum[n_half + 1];
150	
151	  for (int i = 1; i <= n; i++) {
152	    for (int j = n_half - i; j >= -n_half; j--)
153	      MODULO(q) matrix_sum[j][i] = matrix_sum[j + 1][i - 1] - matrix_sum[j][i - 1];
154	  }
155	  matrix_sum[-n_half + 1][n] = matrix_sum[-n_half][n];
156	  for (int j = -n_half + 2; j <= n_half; j++) {
157	    matrix_sum[j][n] = matrix_sum[j - 1][n];
158	    for (int i = n - 1; i >= n_half - j + 1; i--) {
159	      int res = bn_mod_add_fixed_top(matrix_sum[j][i], matrix_sum[j - 1][i], matrix_sum[j - 1][i + 1], q_value);
160	      cb_assert(res && "matrix_sum[j][i] = matrix_sum[j - 1][i] + matrix_sum[j - 1][i + 1] (mod q) failed");
161	    }
162	  }
163	
164	  fischlin_prove(
165	      params,
166	      // initialize
167	      [&]() {
168	        for (int i = 0; i < rho; i++) {
169	          r[i] = bn_t::rand(q);
170	          R[i] = r[i] * G;
171	        }
172	        common_hash = crypto::ro::hash_string(G, Q, R, session_id, aux).bitlen(2 * SEC_P_COM);
173	      },
174	
175	      // response_begin
176	      [&](int i) {
177	        ri = r[i];
178	        int32_t ei = 0 - n_half;
179	        MODULO(q) { z_tag = ri + matrix_sum[ei][0]; }
180	      },
181	
182	      // hash
183	      [&](int i, int try_number) -> uint32_t {
184	        int ei = try_number - n_half;
185	        return hash32bit_for_zk_fischlin(common_hash, i, ei, z_tag);
186	      },
187	
188	      // save
189	      [&](int i, int try_number) {
190	        int ei = try_number - n_half;
191	        e[i] = ei;
192	        z[i] = z_tag;
193	      },
194	
195	      // response_next
196	      [&](int try_number) {
197	        int ei = try_number - n_half;
198	        if (ei > k) {
199	          current->at(n) = last->at(n);
200	          for (int i = n - 1; i >= 0; i--) {
201	            int res = bn_mod_add_fixed_top(current->at(i), last->at(i), last->at(i + 1), q_value);
202	            cb_assert(res);
203	          }
204	          sum[ei] = current->at(0);
205	          std::swap(current, last);
206	          k++;
207	        }
208	
209	        int res = bn_mod_add_fixed_top(z_tag, ri, sum[ei], q_value);
210	        cb_assert(res && "z' = z' + sum[ei] (mod q) failed");
211	      });
212	}
