10	// for example, if only 13 bits used from each 16 bits block (uint16_t),
11	// then 16 bits are used for simpler splitting using uint16_t
12	template <int item_bitlen>
13	class uint_mem_array_t {
14	 private:
15	  const_byte_ptr ptr;
16	
17	 public:
18	  uint_mem_array_t(mem_t mem) : ptr(mem.data) {}
19	  unsigned operator[](int index) const {
20	    constexpr int byte_len = (item_bitlen + CHAR_BIT - 1) / CHAR_BIT;
21	    static_assert(byte_len == 2, "unsupported bitlen");
22	    constexpr unsigned mask = unsigned(-1) >> ((sizeof(unsigned) * CHAR_BIT) - item_bitlen);
23	    return coinbase::be_get_2(ptr + index * byte_len) & mask;
24	  }
25	};
